private async Task<(bool IsSuccess, string Content)> SendHttpRequestAsync(HttpClient httpClient, string endpoint, string errorContext)
{
    try
    {
        HttpResponseMessage response = await httpClient.GetAsync(endpoint);
        if (!response.IsSuccessStatusCode)
        {
            AddError($"{errorContext}: کد وضعیت {response.StatusCode}");
            return (false, string.Empty);
        }

        string content = await response.Content.ReadAsStringAsync();
        var mediaType = response.Content.Headers.ContentType?.MediaType;
        var trimmed = content.AsSpan().TrimStart();
        var looksLikeHtml = trimmed.StartsWith("<", StringComparison.Ordinal)
            || (mediaType is not null
                && mediaType.Contains("html", StringComparison.OrdinalIgnoreCase));

        if (looksLikeHtml || string.IsNullOrWhiteSpace(content))
        {
            var preview = content.Length <= 120 ? content : content[..120];
            AddError($"{errorContext}: پاسخ JSON معتبر نیست (Content-Type={mediaType ?? " mag"}). پیش‌نمایش: {preview}");
            _logger.LogWarning(
                "{ErrorContext}: non-JSON response from {Endpoint}. Content-Type={ContentType}, Length={Length}",
                errorContext,
                endpoint,
                mediaType,
                content.Length);
            return (false, string.Empty);
        }

        return (true, content);
    }
    catch (HttpRequestException ex)
    {
        AddError($"{errorContext}: خطا در اتصال به سرور: {ex.Message}");
        return (false, string.Empty);
    }
    catch (TaskCanceledException ex)
    {
        AddError($"{errorContext}: تایم‌اوت درخواست: {ex.Message}");
        return (false, string.Empty);
    }
    catch (Exception ex)
    {
        AddError($"{errorContext}: خطای غیرمنتظره: {ex.Message}");
        return (false, string.Empty);
    }
}
